from fastapi import FastAPI
from fastapi.testclient import TestClient

from agentpulse.api.v2 import queries
from agentpulse.api.v2 import router as v2_router
from agentpulse.api.v2.ids import derive_process_id
from agentpulse.db import close_db, init_db
from agentpulse.platforms.claude import schema
from agentpulse.platforms.claude.pid_watcher import run_pid_watcher_tick


@pytest.fixture
async def db(tmp_path: Path):
    conn = await init_db(db_path=tmp_path / "test.db")
    yield conn
    await close_db()


@pytest.fixture
def client(db) -> TestClient:
    app = FastAPI()
    app.include_router(v2_router)
    return TestClient(app)


async def _seed_hook(
    db,
    *,
    session_id: str,
    pid: int,
    received_at: float,
    source_system: str = "host",
    cwd: str = "/proj",
    event_name: str = "PreToolUse",
    tool_name: str | None = "Bash",
) -> None:
    payload = {
        "session_id": session_id,
        "hook_event_name": event_name,
        "tool_name": tool_name or "",
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
    }
    await schema.insert_log_hook(
        db,
        payload=payload,
        received_at=received_at,
        received_by="test",
    )
    await db.commit()


async def _seed_statusline(
    db,
    *,
    session_id: str,
    pid: int,
    received_at: float,
    cost_usd: float = 1.0,
    source_system: str = "host",
    cwd: str = "/proj",
) -> None:
    payload = {
        "session_id": session_id,
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
        "cost": {"total_cost_usd": cost_usd},
    }
    await schema.insert_log_statusline(
        db,
        payload=payload,
        received_at=received_at,
        received_by="test",
    )
    await db.commit()


async def _seed_death(
    db, *, pid: int, observed_at: float, source_system: str = "host", cwd: str = "/proj"
) -> None:
    await schema.insert_log_pid_death(
        db,
        pid=pid,
        source_system=source_system,
        cwd=cwd,
        observed_at=observed_at,
        observed_by="pid-watcher",
    )
    await db.commit()


async def _seed_reuse_scenario(db) -> None:
    """Two instances on the same (pid=4242, host, /proj) tuple.

    Instance 1: hook at t=10, death at t=100.
    Instance 2: hook at t=200 (alive — no closing death).
    """
    await _seed_hook(db, session_id="s1", pid=4242, received_at=10.0)
    await _seed_death(db, pid=4242, observed_at=100.0)
    await _seed_hook(db, session_id="s2", pid=4242, received_at=200.0)


# ---- get_processes returns one row per instance -----------------------------


class TestGetProcessesPerInstance:
    async def test_get_processes_returns_one_row_per_instance(self, db) -> None:
        await _seed_reuse_scenario(db)
        procs = await queries.get_processes(db)
        assert len(procs) == 2

    async def test_alive_instance_pid_alive_true_after_prior_death(self, db) -> None:
        await _seed_reuse_scenario(db)
        procs = await queries.get_processes(db)
        # Sort by started_at to identify which is which
        procs_sorted = sorted(procs, key=lambda p: p["started_at"])
        instance_1 = procs_sorted[0]
        instance_2 = procs_sorted[1]
        assert instance_1["pid_alive"] is False
        assert instance_2["pid_alive"] is True

    async def test_dead_instance_ended_at_matches_its_own_death(self, db) -> None:
        # Add a second death to make this less ambiguous
        await _seed_hook(db, session_id="s1", pid=4242, received_at=10.0)
        await _seed_death(db, pid=4242, observed_at=100.0)
        await _seed_hook(db, session_id="s2", pid=4242, received_at=200.0)
        await _seed_death(db, pid=4242, observed_at=300.0)

        procs = await queries.get_processes(db)
        assert len(procs) == 2
        procs_sorted = sorted(procs, key=lambda p: p["started_at"])
        assert procs_sorted[0]["ended_at"] == 100.0
        assert procs_sorted[1]["ended_at"] == 300.0

