class TestLogEndpointsPerInstanceProcessId:
    """Raw log endpoints must report the instance's process_id, not the
    tuple-global one. Each row's process_id depends on its received_at
    relative to surrounding deaths.
    """

    def test_log_hooks_endpoint_process_id_per_instance_row(self, client, db) -> None:
        from tests.conftest import run_async

        # Seed the reuse scenario synchronously via run_async
        run_async(_seed_reuse_scenario(db))

        resp = client.get("/api/v2/log/hooks")
        body = resp.json()
        assert len(body) == 2
        # Find by session_id — instance 1 hook has s1, instance 2 has s2
        hook_1 = next(r for r in body if r["session_id"] == "s1")
        hook_2 = next(r for r in body if r["session_id"] == "s2")
        assert hook_1["process_id"] != hook_2["process_id"]

        # Each should match what derive_process_id produces for that instance
        expected_1 = derive_process_id(
            source_system="host", pid=4242, cwd="/proj", earliest_received_at=10.0
        )
        expected_2 = derive_process_id(
            source_system="host", pid=4242, cwd="/proj", earliest_received_at=200.0
        )
        assert hook_1["process_id"] == expected_1
        assert hook_2["process_id"] == expected_2

